class User(UserMixin):
    def __init__(self, username):
        self.username = username
        self.mfa = None
        self.is_active = True

    @property
    def mfa_key(self):
        return self.mfa.totp_secret_base32()

    @mfa_key.setter
    def mfa_key(self, key):
        self.mfa = MFASession(app).from_totp_base32(key)

def generate_mfa():
    return Fernet.generate_key()

@app.route('/enable-mfa', methods=['GET', 'POST'])
@login_required
def enable_mfa():
    if request.method == 'POST':
        user = User(current_user.username)
        user.mfa_key = generate_mfa()
        return redirect(url_for('index'))
    else:
        return render_template('enable-mfa.html')

@app.route('/disable-mfa', methods=['POST'])
@login_required
def disable_mfa():
    user = User(current_user.username)
